import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import axios from 'axios';

function UASTLChart({ range }) {
    const d3Container = useRef(null);

    useEffect(() => {
        let svg;
        let width = d3Container.current.clientWidth;
        let height = d3Container.current.clientHeight;
        let margin = { top: 30, right: 20, bottom: 30, left: 50 };
        let chartW = width - margin.left - margin.right;
        let chartH = height - margin.top - margin.bottom;

        d3.select(d3Container.current).selectAll('*').remove();

        Promise.all([
            axios.get('http://localhost:3001/api/uastl'),
            d3.csv('/CoolWarmFloat257.csv', d => ({
                scalar: +d.Scalar,
                color: d3.rgb(+d.R * 255, +d.G * 255, +d.B * 255).formatHex()
            }))
        ]).then(([res, cmapData]) => {
            let data = res.data;
            if (!data || data.length === 0) return;
            if (range && range.length === 2) data = data.slice(range[0], range[1] + 1);

            const n = data.length;
            const seasonalKeys = Object.keys(data[0]).filter(k => k.startsWith('seasonal') && k.endsWith('_mean'));
            const L = seasonalKeys.length;
            const numComponents = 3 + L;

            // 顏色設定
            const meanColor = '#1a237e'; // navy
            const bandColors = {
                '50%': '#90caf9', // skyblue
                '99%': '#64b5f6'  // lightblue
            };
            const sigmaLevels = {
                '50%': 0.674490,
                '99%': 2.575829
            };
            // 使用 d3.interpolateViridis 替代 schemeViridis
            const sampleColors = [
                d3.interpolateViridis(0.2),
                d3.interpolateViridis(0.5),
                d3.interpolateViridis(0.8)
            ];

            // 建立 SVG
            svg = d3.select(d3Container.current)
                .append('svg')
                .attr('width', width)
                .attr('height', height)
                .style('background', 'none');

            // 計算每個子圖的高度
            const subplotH = chartH / numComponents;

            // 建立 CoolWarm colormap
            const coolwarm = d3.scaleLinear()
                .domain([-1, 0, 1])
                .range([
                    cmapData[0].color,
                    cmapData[Math.floor(cmapData.length / 2)].color,
                    cmapData[cmapData.length - 1].color
                ]);

            // 繪製每個成分
            const componentKeys = {
                'Input Data': ['input_mean', 'input_std', 'corr_input'],
                'Trend Component': ['trend_mean', 'trend_std', 'corr_trend'],
                ...Object.fromEntries(seasonalKeys.map((k, i) => [
                    `Seasonal Component ${i + 1}`,
                    [k, k.replace('_mean', '_std'), `corr_seasonal${i + 1}`]
                ])),
                'Residual Component': ['residual_mean', 'residual_std', 'corr_residual']
            };

            Object.entries(componentKeys).forEach(([title, [meanKey, stdKey, corrKey]], i) => {
                const g = svg.append('g')
                    .attr('transform', `translate(${margin.left},${margin.top + i * subplotH})`);

                const mean = data.map(d => +d[meanKey]);
                const std = data.map(d => +d[stdKey]);
                const corr = data.map(d => +d[corrKey]);

                // Y軸比例尺
                const y = d3.scaleLinear()
                    .domain([
                        d3.min(mean, (d, j) => d - 2.6 * std[j]),
                        d3.max(mean, (d, j) => d + 2.6 * std[j])
                    ]).nice()
                    .range([subplotH - 32, 0]);

                // X軸比例尺
                const x = d3.scaleLinear()
                    .domain([0, n - 1])
                    .range([0, chartW]);

                // 繪製信賴區間
                ['99%', '50%'].forEach(level => {
                    g.append('path')
                        .datum(mean.map((m, j) => ({
                            x: x(j),
                            y0: y(m - sigmaLevels[level] * std[j]),
                            y1: y(m + sigmaLevels[level] * std[j])
                        })))
                        .attr('fill', bandColors[level])
                        .attr('opacity', level === '99%' ? 0.3 : 0.5)
                        .attr('d', d3.area()
                            .x(d => d.x)
                            .y0(d => d.y0)
                            .y1(d => d.y1)
                        );
                });

                // 繪製樣本路徑
                [1, 2, 3].forEach(sampleNum => {
                    const sampleKey = `sample${sampleNum}_${meanKey.split('_')[0]}`;
                    if (data[0][sampleKey] !== undefined) {
                        const sample = data.map(d => +d[sampleKey]);
                        g.append('path')
                            .datum(sample)
                            .attr('fill', 'none')
                            .attr('stroke', sampleColors[sampleNum - 1])
                            .attr('stroke-width', 0.5)
                            .attr('opacity', 0.7)
                            .attr('d', d3.line()
                                .x((d, idx) => x(idx))
                                .y(d => y(d))
                            );
                    }
                });

                // 繪製均值線
                g.append('path')
                    .datum(mean)
                    .attr('fill', 'none')
                    .attr('stroke', meanColor)
                    .attr('stroke-width', 1.5)
                    .attr('d', d3.line()
                        .x((d, idx) => x(idx))
                        .y(d => y(d))
                    );

                // --------- 這裡重構底部紅藍色帶 ---------
                const barHeight = subplotH / 8;
                const barY = subplotH - 32 - barHeight; // 貼齊底部
                const barW = chartW / n;
                for (let idx = 0; idx < n; idx++) {
                    if (isNaN(corr[idx])) continue;
                    g.append('rect')
                        .attr('x', x(idx) - barW / 2)
                        .attr('y', barY)
                        .attr('width', barW)
                        .attr('height', barHeight)
                        .attr('fill', coolwarm(corr[idx]))
                        .attr('stroke', 'none');
                }
                // --------------------------------------

                // 標題
                g.append('text')
                    .attr('x', chartW / 2)
                    .attr('y', -8)
                    .attr('fill', meanColor)
                    .attr('font-size', 18)
                    .attr('font-family', 'Arial')
                    .attr('font-weight', 'bold')
                    .attr('text-anchor', 'middle')
                    .text(title);

                // Y軸
                g.append('g')
                    .call(d3.axisLeft(y).ticks(4))
                    .selectAll('text')
                    .attr('fill', meanColor)
                    .attr('font-family', 'Arial');

                // X軸（只在最後一個子圖）
                if (i === numComponents - 1) {
                    g.append('g')
                        .attr('transform', `translate(0,${subplotH - 32})`)
                        .call(d3.axisBottom(x).ticks(10))
                        .selectAll('text')
                        .attr('fill', meanColor)
                        .attr('font-family', 'Arial');
                }
            });
        });
    }, [range]);

    return (
        <div style={{ width: '100%', height: '100%', background: 'none' }}>
            <div ref={d3Container} style={{ width: '100%', height: '100%', borderRadius: '12px', overflow: 'hidden', position: 'relative' }} />
        </div>
    );
}

export default UASTLChart;
